import PropTypes from 'prop-types'
import React, { useMemo } from 'react'

export const KyokuyaSudokuBoardBorders: React.FC<{ SUDOKU_SIZE_SQRT: number }> =
  ({ SUDOKU_SIZE_SQRT }) => {
    const borders = useMemo<React.ReactNode[]>(() => {
      const SUDOKU_SIZE = SUDOKU_SIZE_SQRT * SUDOKU_SIZE_SQRT
      const borders: React.ReactNode[] = []
      for (
        let i = SUDOKU_SIZE_SQRT, j = -1;
        i < SUDOKU_SIZE;
        i += SUDOKU_SIZE_SQRT, ++j
      ) {
        const position = `calc(${i} * var(--kyokuya-sudoku__board-cell-size) + ${
          i + j
        }px)`
        borders.push(
          <div
            key={`h-${i}`}
            className="kyokuya-sudoku__board-horizontal-border"
            style={{ top: position }}
          />,
        )
        borders.push(
          <div
            key={`v-${i}`}
            className="kyokuya-sudoku__board-vertical-border"
            style={{ left: position }}
          />,
        )
      }
      return borders
    }, [SUDOKU_SIZE_SQRT])

    return <React.Fragment>{borders}</React.Fragment>
  }

KyokuyaSudokuBoardBorders.propTypes = {
  SUDOKU_SIZE_SQRT: PropTypes.number.isRequired,
}

KyokuyaSudokuBoardBorders.displayName = 'KyokuyaSudokuBoardBorders'
export default KyokuyaSudokuBoardBorders
