import React from 'react'
import type { KyokuyaSudokuAction } from './actions'
import type { KyokuyaSudokuContextData } from './state'
import { initKyokuyaSudokuContextData } from './state'

/**
 * Side-effect funcs provided by the KyokuyaSudokuContext.
 */
export interface KyokuyaSudokuContextState extends KyokuyaSudokuContextData {
  /**
   * Update the context data.
   */
  dispatch: React.Dispatch<KyokuyaSudokuAction>
}

/**
 * Create sudoku context.
 */
export const KyokuyaSudokuContext: React.Context<KyokuyaSudokuContextState> =
  React.createContext({
    ...initKyokuyaSudokuContextData(),
    dispatch: (): never => {
      throw new Error(`No available dispatch prepared yet.`)
    },
  } as KyokuyaSudokuContextState)
