import type { SudokuBoard } from '@algorithm.ts/sudoku'
import cn from 'clsx'
import PropTypes from 'prop-types'
import React, { useCallback, useContext } from 'react'
import { KyokuyaSudokuActionsType } from '../context/actions'
import { KyokuyaSudokuContext } from '../context/context'
import KyokuyaSudokuBoardBorders from './SudokuBoardBorders'
import './style.styl'

export interface KyokuyaSudokuBoardProps {
  /**
   * An attempt at a puzzle.
   */
  attempt: Readonly<SudokuBoard>
  /**
   * Duplicated grids
   */
  duplicatedMap?: ReadonlyArray<ReadonlyArray<boolean>>
  /**
   * CSS class name.
   */
  className?: string
  /**
   * Sudoku board overlay.
   */
  overlay?: React.ReactNode
  /**
   * Callback function triggered when a grid is clicked.
   */
  onCellClick?(r: number, c: number): void
}

/**
 * Render a sudoku board.
 *
 * @param props
 * @returns
 */
export const KyokuyaSudokuBoard: React.FC<KyokuyaSudokuBoardProps> = props => {
  const {
    SUDOKU_SIZE_SQRT,
    radix,
    puzzle,
    segmentNoMap,
    activatedCell,
    hintCell,
    hintTick,
    dispatch,
  } = useContext(KyokuyaSudokuContext)

  const { attempt, duplicatedMap, className, overlay, onCellClick } = props
  const handleCellClick = useCallback(
    (r: number, c: number) => {
      if (onCellClick != null) onCellClick(r, c)
      dispatch({
        type: KyokuyaSudokuActionsType.ACTIVE,
        payload: { r, c },
      })
    },
    [dispatch, onCellClick],
  )

  const { r: R, c: C } = activatedCell
  const V = R === -1 ? -1 : attempt[R][C]
  const R0 = R === -1 ? -1 : segmentNoMap[R]
  const C0 = C === -1 ? -1 : segmentNoMap[C]
  const { r: hr, c: hc, v: hv } = hintCell

  return (
    <div className={cn('kyokuya-sudoku__board', className)}>
      <div key="overlay" className="kyokuya-sudoku__board-overlay">
        {overlay}
      </div>
      <KyokuyaSudokuBoardBorders SUDOKU_SIZE_SQRT={SUDOKU_SIZE_SQRT} />
      <div key="wrapper" className="kyokuya-sudoku__board-wrapper">
        {attempt.map((row, r) => (
          <div key={r} className="kyokuya-sudoku__board-row">
            {row.map((v, c) => {
              const isHint: boolean = r === hr && c === hc
              const isActivated: boolean = r === R && c === C
              const isDuplicated: boolean =
                duplicatedMap !== undefined && duplicatedMap[r][c]
              const isRelate: boolean =
                !isActivated &&
                (r === R ||
                  c === C ||
                  (segmentNoMap[r] === R0 && segmentNoMap[c] === C0))
              const isSame: boolean =
                V === -1 ? false : v === V && !isRelate && !isActivated

              const vv = isHint ? hv : v
              return (
                <span
                  key={isHint ? `${c}-hint-${hintTick}` : c}
                  className={cn('kyokuya-sudoku__board-cell', {
                    'kyokuya-sudoku__board-cell--left-seamless': c === 0,
                    'kyokuya-sudoku__board-cell--left':
                      c > 0 && c % SUDOKU_SIZE_SQRT === 0,
                    'kyokuya-sudoku__board-cell--top-seamless': r === 0,
                    'kyokuya-sudoku__board-cell--top':
                      r > 0 && r % SUDOKU_SIZE_SQRT === 0,
                    'kyokuya-sudoku__board-cell--preset': v !== -1,
                    'kyokuya-sudoku__board-cell--attempt': v !== puzzle[r][c],
                    'kyokuya-sudoku__board-cell--duplicated': isDuplicated,
                    'kyokuya-sudoku__board-cell--hint': isHint,
                    'kyokuya-sudoku__board-cell--activated': isActivated,
                    'kyokuya-sudoku__board-cell--related': isRelate,
                    'kyokuya-sudoku__board-cell--same': isSame,
                  })}
                >
                  <span
                    className="kyokuya-sudoku__board-cell-content"
                    onClick={() => handleCellClick(r, c)}
                  >
                    {vv === -1 ? '' : (vv + 1).toString(radix)}
                  </span>
                </span>
              )
            })}
          </div>
        ))}
      </div>
    </div>
  )
}

KyokuyaSudokuBoard.propTypes = {
  attempt: PropTypes.array.isRequired,
  duplicatedMap: PropTypes.array,
  className: PropTypes.string,
  overlay: PropTypes.node,
  onCellClick: PropTypes.func,
}

KyokuyaSudokuBoard.displayName = 'KyokuyaSudokuBoard'
export default KyokuyaSudokuBoard
